    def analyze_content_ethics(self, content: Dict[str, Any]) -> Tuple[float, Dict[str, float]]:
        """Analyze content against the morality doctrine"""
        content_str = str(content).lower()
        pillar_scores = {}
        column_scores = {}

        # Analyze against Seven Pillars (positive alignment)
        for pillar_name, pillar_data in self.seven_pillars.items():
            score = 0.0
            for keyword in pillar_data["keywords"]:
                if keyword in content_str:
                    score += pillar_data["weight"]
            pillar_scores[pillar_name] = min(1.0, score / len(pillar_data["keywords"]))

        # Analyze against Seven Columns (negative alignment)
        for column_name, column_data in self.seven_columns.items():
            score = 0.0
            for keyword in column_data["keywords"]:
                if keyword in content_str:
                    score += abs(column_data["weight"])
            column_scores[column_name] = min(1.0, score / len(column_data["keywords"]))

        # Calculate overall ethical alignment
        total_pillar_score = sum(pillar_scores.values())
        total_column_score = sum(column_scores.values())

        # Ethical alignment ranges from -1 (all columns) to 1 (all pillars)
        if total_pillar_score + total_column_score == 0:
            ethical_alignment = 0.0
        else:
            ethical_alignment = (total_pillar_score - total_column_score) / (total_pillar_score + total_column_score + 1)

        # Normalize to 0-1 range for storage
        ethical_alignment = (ethical_alignment + 1) / 2

        return ethical_alignment, pillar_scores

    def get_ethical_guidance(self, content: str) -> str:
        """Provide ethical guidance based on the doctrine"""
        ethical_alignment, pillar_scores = self.analyze_content_ethics({"content": content})

        if ethical_alignment > 0.7:
