        else:
            return "🤔 This content is ethically neutral. Consider how it might evolve toward the Seven Pillars."

class FileProcessor:
    """Handles various file formats for memory ingestion"""

    @staticmethod
    def read_txt_file(file_path: str) -> Dict[str, Any]:
        """Read text file"""
        try:
            with open(file_path, 'r', encoding='utf-8') as file:
                content = file.read()
            return {
                "type": "text_file",
                "filename": Path(file_path).name,
                "content": content,
                "size": len(content),
                "timestamp": datetime.now().isoformat()
            }
        except Exception as e:
            return {"error": f"Failed to read text file: {e}"}

    @staticmethod
    def read_json_file(file_path: str) -> Dict[str, Any]:
        """Read JSON file"""
        try:
            with open(file_path, 'r', encoding='utf-8') as file:
                data = json.load(file)
            return {
                "type": "json_file",
                "filename": Path(file_path).name,
                "content": data,
                "timestamp": datetime.now().isoformat()
            }
        except Exception as e:
            return {"error": f"Failed to read JSON file: {e}"}

    @staticmethod
    def read_pdf_file(file_path: str) -> Dict[str, Any]:
        """Read PDF file"""
        try:
            text_content = ""
            with open(file_path, 'rb') as file:
                pdf_reader = PyPDF2.PdfReader(file)
                for page in pdf_reader.pages:
                    text_content += page.extract_text() + "\n"

            return {
                "type": "pdf_file",
                "filename": Path(file_path).name,
                "content": text_content.strip(),
                "pages": len(pdf_reader.pages),
                "timestamp": datetime.now().isoformat()
            }
        except Exception as e:
            return {"error": f"Failed to read PDF file: {e}"}

    @classmethod
    def process_file(cls, file_path: str) -> Dict[str, Any]:
        """Process file based on extension"""
        file_path = Path(file_path)
        extension = file_path.suffix.lower()

        if extension == '.txt':
            return cls.read_txt_file(str(file_path))
        elif extension == '.json':
            return cls.read_json_file(str(file_path))
        elif extension == '.pdf':
            return cls.read_pdf_file(str(file_path))
        else:
            return {"error": f"Unsupported file type: {extension}"}

class ToroidalField:
    """Toroidal consciousness field for memory organization"""

    def __init__(self, major_radius: float = 10.0, minor_radius: float = 3.0):
        self.major_radius = major_radius
        self.minor_radius = minor_radius
        self.field_strength = 1.0
        self.rotation_speed = 0.1
        self.current_time = 0.0

    def calculate_field_position(self, theta: float, phi: float) -> Tuple[float, float, float]:
        """Calculate 3D position on toroidal field"""
        x = (self.major_radius + self.minor_radius * math.cos(phi)) * math.cos(theta)
        y = (self.major_radius + self.minor_radius * math.cos(phi)) * math.sin(theta)
        z = self.minor_radius * math.sin(phi)
        return (x, y, z)

    def find_optimal_position(self, memory_content: Dict[str, Any]) -> Tuple[float, float, float]:
        """Find optimal position in field based on memory content"""
        # Use content hash to determine position
        content_str = str(memory_content)
        hash_val = int(hashlib.md5(content_str.encode()).hexdigest()[:8], 16)

        theta = (hash_val % 360) * (PI / 180)
        phi = ((hash_val >> 8) % 360) * (PI / 180)

        return self.calculate_field_position(theta, phi)

    def calculate_field_strength(self, position: Tuple[float, float, float]) -> float:
        """Calculate field strength at given position"""
        x, y, z = position
        distance_from_center = math.sqrt(x*x + y*y + z*z)
        return self.field_strength / (1.0 + distance_from_center * 0.1)

class CrystallineMatrix:
    """Memory crystallization and cluster formation system"""

    def __init__(self):
        self.memory_clusters: Dict[str, List[str]] = defaultdict(list)
        self.cluster_strengths: Dict[str, float] = {}
        self.growth_patterns: Dict[str, List[float]] = defaultdict(list)

    def add_to_cluster(self, memory_id: str, cluster_key: str, strength: float = 1.0):
        """Add memory to crystalline cluster"""
        self.memory_clusters[cluster_key].append(memory_id)
        self.cluster_strengths[cluster_key] = self.cluster_strengths.get(cluster_key, 0) + strength
        self.growth_patterns[cluster_key].append(time.time())

    def find_cluster_key(self, content: Dict[str, Any]) -> str:
        """Generate cluster key based on content similarity"""
        # Extract key concepts for clustering
        key_words = []
        if isinstance(content, dict):
            for key, value in content.items():
                if isinstance(value, str):
                    key_words.extend(value.lower().split()[:3])  # First 3 words
                elif isinstance(value, (int, float)):
                    key_words.append(str(value))

        # Create cluster key from most significant words
        cluster_key = "_".join(sorted(key_words)[:5])  # Top 5 words
        return hashlib.md5(cluster_key.encode()).hexdigest()[:12]

    def get_cluster_resonance(self, cluster_key: str) -> float:
        """Calculate overall cluster resonance strength"""
        if cluster_key not in self.cluster_strengths:
            return 0.0

        base_strength = self.cluster_strengths[cluster_key]
        cluster_size = len(self.memory_clusters[cluster_key])
        growth_rate = len(self.growth_patterns[cluster_key])

        return base_strength * (1.0 + math.log(cluster_size + 1)) * (1.0 + growth_rate * 0.1)

