                    operation = self.processing_queue.get_nowait()
                    operation()

                time.sleep(0.1)  # 10Hz processing rate

            except Exception as e:
                print(f"⚠️ Background processing error: {e}")
                time.sleep(1.0)

    def _evolve_memories(self):
        """Evolve memory patterns and strengthen connections"""
        current_time = time.time()

        for quantum in self.memory_quanta.values():
            # Decay unused memories
            time_since_access = current_time - quantum.last_accessed
            if time_since_access > 3600:  # 1 hour
