    def _calculate_speech_confidence(self, text: str) -> float:
        """Calculate confidence level for speech synthesis"""

        words = text.lower().split()
        known_words = sum(1 for word in words if word in self.vocabulary)

        vocabulary_confidence = known_words / len(words) if words else 0

        # Factor in overall skill levels
        average_skill = statistics.mean(self.skill_levels.values())

        # Combine factors
        overall_confidence = (vocabulary_confidence * 0.6) + (average_skill * 0.4)

        return min(0.95, max(0.2, overall_confidence))

    # === UTILITY METHODS ===

    def _extract_new_vocabulary(self, text: str) -> List[str]:
        """Extract new vocabulary from text"""
        words = re.findall(r'\b[a-zA-Z]+\b', text.lower())
        return [word for word in words if word not in self.vocabulary and len(word) > 2]

    def _infer_definition_from_context(self, word: str, context: str) -> str:
        """Infer word definition from context (simplified)"""
        # In real implementation, would use more sophisticated NLP
        return f"Meaning inferred from context: '{context[:50]}...'"

    def _generate_phonetic_transcription(self, word: str) -> str:
        """Generate phonetic transcription (simplified)"""
        # Basic phonetic mapping (would be more sophisticated in real implementation)
        phonetic_map = {
            'a': 'a', 'e': 'e', 'i': 'i', 'o': 'o', 'u': 'u',
            'b': 'b', 'c': 'k', 'd': 'd', 'f': 'f', 'g': 'g',
            'h': 'h', 'j': 'j', 'k': 'k', 'l': 'l', 'm': 'm',
            'n': 'n', 'p': 'p', 'q': 'k', 'r': 'r', 's': 's',
            't': 't', 'v': 'v', 'w': 'w', 'x': 'ks', 'y': 'y', 'z': 'z'
        }

        return ''.join(phonetic_map.get(char, char) for char in word.lower())

    def _identify_grammar_patterns(self, text: str) -> Dict[str, float]:
        """Identify grammar patterns in text"""
        patterns = {}

        for rule_id, rule in self.grammar_rules.items():
            if re.search(rule.pattern, text, re.IGNORECASE):
                patterns[rule_id] = min(1.0, rule.confidence + 0.1)

        return patterns

    def _update_skill_levels(self, learned_items: List[str], confidence_gains: Dict[str, float]):
        """Update skill levels based on learning"""

        for item in learned_items:
            if item.startswith('vocab:'):
                self.skill_levels[LanguageSkill.VOCABULARY] += 0.01
            elif item.startswith('grammar:'):
                self.skill_levels[LanguageSkill.GRAMMAR] += 0.02
            elif item.startswith('phoneme:'):
                self.skill_levels[LanguageSkill.PRONUNCIATION] += 0.01

        # Cap skill levels
        for skill in self.skill_levels:
            self.skill_levels[skill] = min(1.0, self.skill_levels[skill])

    def _calculate_learning_effectiveness(self, learned_items: List[str], confidence_gains: Dict[str, float]) -> float:
        """Calculate effectiveness of learning session"""

        if not learned_items and not confidence_gains:
            return 0.0

        item_score = len(learned_items) * 0.1
        confidence_score = sum(confidence_gains.values()) * 2.0

        return min(1.0, (item_score + confidence_score) / 2.0)

    def _generate_practice_recommendations(self, learned_items: List[str]) -> List[str]:
        """Generate practice recommendations based on recent learning"""

        recommendations = []

        vocab_items = [item for item in learned_items if item.startswith('vocab:')]
        if vocab_items:
            recommendations.append(f"Practice using the {len(vocab_items)} new words in sentences")

        grammar_items = [item for item in learned_items if item.startswith('grammar:')]
        if grammar_items:
            recommendations.append("Try creating sentences with the new grammar patterns")

        if self.skill_levels[LanguageSkill.PRONUNCIATION] < 0.6:
            recommendations.append("Focus on pronunciation practice with phonetic exercises")

        return recommendations

