    def _suggest_next_learning_goals(self) -> List[str]:
        """Suggest next learning goals based on current progress"""

        goals = []

        # Vocabulary goals
        if len(self.vocabulary) < 1000:
            goals.append(f"Build vocabulary to 1000 words (currently {len(self.vocabulary)})")
        elif len(self.vocabulary) < 5000:
            goals.append(f"Expand vocabulary to 5000 words (currently {len(self.vocabulary)})")

        # Grammar goals
        if len(self.grammar_rules) < 50:
            goals.append("Master basic grammar patterns and sentence structures")

        # Speech goals
        overall_confidence = self._calculate_overall_speech_confidence()
        if overall_confidence < 0.7:
            goals.append("Improve speech synthesis confidence through practice")

        # Multimodal goals
        video_sessions = len([s for s in self.learning_history if s.source == LearningMethod.VIDEO_ANALYSIS])
        if video_sessions < 10:
            goals.append("Engage in more visual-contextual learning through video analysis")

        return goals

    def _calculate_overall_speech_confidence(self) -> float:
        """Calculate overall confidence level for speech synthesis"""

        # Weight different skills for speech confidence
        weights = {
            LanguageSkill.VOCABULARY: 0.25,
            LanguageSkill.GRAMMAR: 0.20,
            LanguageSkill.PRONUNCIATION: 0.25,
            LanguageSkill.INTONATION: 0.15,
            LanguageSkill.EMOTION_MAPPING: 0.10,
            LanguageSkill.TIMING: 0.05
        }

        weighted_confidence = sum(
            self.skill_levels[skill] * weight 
            for skill, weight in weights.items()
        )

        return weighted_confidence

    def _assess_synthesis_readiness(self) -> Dict[str, Any]:
        """Assess readiness for different types of speech synthesis"""

        overall_confidence = self._calculate_overall_speech_confidence()

        return {
            'basic_responses': overall_confidence > 0.4,
            'emotional_speech': (
                overall_confidence > 0.6 and 
                self.skill_levels[LanguageSkill.EMOTION_MAPPING] > 0.5
            ),
            'natural_conversation': (
                overall_confidence > 0.7 and
                self.skill_levels[LanguageSkill.INTONATION] > 0.6 and
                self.skill_levels[LanguageSkill.TIMING] > 0.5
            ),
            'complex_topics': (
                overall_confidence > 0.8 and
                len(self.vocabulary) > 2000 and
                self.skill_levels[LanguageSkill.GRAMMAR] > 0.7
            )
        }

    def _calculate_recommended_practice_time(self) -> Dict[str, int]:
        """Calculate recommended practice time in minutes per day"""

        overall_confidence = self._calculate_overall_speech_confidence()

        if overall_confidence < 0.3:
            return {
                'vocabulary_practice': 20,
                'pronunciation_practice': 15,
                'conversation_practice': 10,
                'total_daily': 45
            }
        elif overall_confidence < 0.6:
            return {
                'vocabulary_practice': 15,
                'pronunciation_practice': 10,
                'conversation_practice': 15,
                'total_daily': 40
            }
        elif overall_confidence < 0.8:
            return {
                'vocabulary_practice': 10,
                'pronunciation_practice': 5,
                'conversation_practice': 20,
                'total_daily': 35
            }
        else:
            return {
                'vocabulary_practice': 5,
                'pronunciation_practice': 5,
                'conversation_practice': 15,
                'total_daily': 25
            }

