    def _analyze_conversation_flow_patterns(self):
        """Analyze patterns in conversation flow"""

        recent_inputs = [entry['user_input'] for entry in self.conversation_context[-3:]]

        # Look for question-answer patterns
        question_pattern = any('?' in inp for inp in recent_inputs)
        if question_pattern:
            self.skill_levels[LanguageSkill.CULTURAL_CONTEXT] += 0.005

        # Look for emotional continuity
        emotional_words = ['happy', 'sad', 'excited', 'worried', 'love', 'hate', 'enjoy']
        emotional_continuity = sum(
