    def _calculate_speech_confidence(self, text: str) -> float:
        """Calculate confidence level for speech synthesis"""

        words = text.lower().split()
        known_words = sum(1 for word in words if word in self.vocabulary)

        vocabulary_confidence = known_words / len(words) if words else 0

        # Factor in overall skill levels
        average_skill = statistics.mean(self.skill_levels.values())

        # Combine factors
