                patterns[rule_id] = min(1.0, rule.confidence + 0.1)

        return patterns

    def _update_skill_levels(self, learned_items: List[str], confidence_gains: Dict[str, float]):
        """Update skill levels based on learning"""

        for item in learned_items:
            if item.startswith('vocab:'):
                self.skill_levels[LanguageSkill.VOCABULARY] += 0.01
            elif item.startswith('grammar:'):
                self.skill_levels[LanguageSkill.GRAMMAR] += 0.02
            elif item.startswith('phoneme:'):
                self.skill_levels[LanguageSkill.PRONUNCIATION] += 0.01

        # Cap skill levels
        for skill in self.skill_levels:
            self.skill_levels[skill] = min(1.0, self.skill_levels[skill])

    def _calculate_learning_effectiveness(self, learned_items: List[str], confidence_gains: Dict[str, float]) -> float:
        """Calculate effectiveness of learning session"""

        if not learned_items and not confidence_gains:
            return 0.0

        item_score = len(learned_items) * 0.1
        confidence_score = sum(confidence_gains.values()) * 2.0

        return min(1.0, (item_score + confidence_score) / 2.0)

