    async def import_learning_state(self, state_data: Dict[str, Any]) -> bool:
        """Import learning state from saved data"""

        try:
            # Import skill levels
            if 'skill_levels' in state_data:
                for skill_name, level in state_data['skill_levels'].items():
                    skill = LanguageSkill(skill_name)
                    self.skill_levels[skill] = level

            # Import vocabulary
            if 'vocabulary' in state_data:
                for word, entry_data in state_data['vocabulary'].items():
                    entry = VocabularyEntry(
                        word=entry_data['word'],
                        definitions=entry_data['definitions'],
                        phonetic=entry_data['phonetic'],
                        frequency=entry_data['frequency'],
                        emotional_associations=entry_data.get('emotional_associations', {}),
                        contextual_usage=entry_data.get('contextual_usage', []),
                        pronunciation_confidence=entry_data.get('pronunciation_confidence', 0.5),
                        learning_source=LearningMethod(entry_data.get('learning_source', 'interaction'))
                    )
                    self.vocabulary[word] = entry

            # Import grammar rules
            if 'grammar_rules' in state_data:
                for rule_id, rule_data in state_data['grammar_rules'].items():
                    rule = GrammarRule(
                        rule_id=rule_data['rule_id'],
                        description=rule_data['description'],
                        pattern=rule_data['pattern'],
                        examples=rule_data['examples'],
                        confidence=rule_data['confidence'],
                        usage_count=rule_data['usage_count'],
                        exceptions=rule_data.get('exceptions', [])
                    )
                    self.grammar_rules[rule_id] = rule

            # Import speech patterns
            if 'speech_patterns' in state_data:
                for pattern_id, pattern_data in state_data['speech_patterns'].items():
                    pattern = SpeechPattern(
                        pattern_id=pattern_data['pattern_id'],
                        template=pattern_data['template'],
                        emotional_context=pattern_data['emotional_context'],
                        timing_cues=pattern_data['timing_cues'],
                        intonation_curve=pattern_data['intonation_curve'],
                        confidence=pattern_data['confidence']
                    )
                    self.speech_patterns[pattern_id] = pattern

            # Import phonetic inventory
            if 'phonetic_inventory' in state_data:
                for phoneme, pattern_data in state_data['phonetic_inventory'].items():
                    pattern = PhoneticPattern(
                        phoneme=pattern_data['phoneme'],
                        frequency_range=tuple(pattern_data['frequency_range']),
                        duration_ms=pattern_data['duration_ms'],
                        intensity=pattern_data['intensity'],
                        emotional_modifier=pattern_data.get('emotional_modifier', 1.0)
                    )
                    self.phonetic_inventory[phoneme] = pattern

            # Import other components
            self.learning_preferences = state_data.get('learning_preferences', {})
            self.emotion_speech_mapping = state_data.get('emotion_speech_mapping', {})
            self.prosody_models = state_data.get('prosody_models', {})
            self.rhythm_patterns = state_data.get('rhythm_patterns', {})

            return True

        except Exception as e:
            print(f"Error importing learning state: {e}")
            return False

