            calculateTraitScore(text, keywords, min, max, inverse = false) {
                let score = 0;
                keywords.forEach(keyword => {
                    score += (text.match(new RegExp(keyword, 'g')) || []).length;
                });

                const normalizedScore = Math.min(score / 50, 1); // Normalize to 0-1
                const finalScore = min + (normalizedScore * (max - min));

                return inverse ? max - finalScore + min : finalScore;
            }

