                        <p><strong>Statements:</strong> ${this.analysisResults.communicationStyle?.statements?.toFixed(1) || 'N/A'}% of interactions</p>
                    </div>

                    <div class="personality-profile">
                        <h4>🎯 Primary Interests</h4>
                        ${Object.entries(this.analysisResults.topicInterests || {}).map(([topic, score]) => `
                            <p><strong>${topic.charAt(0).toUpperCase() + topic.slice(1)}:</strong> ${score} mentions</p>
                        `).join('')}
                    </div>
                `;
            }

            async resurrectAI() {
                const progressSection = document.getElementById('progressSection');
                const progressFill = document.getElementById('progressFill');
                const progressText = document.getElementById('progressText');
                const progressTitle = document.getElementById('progressTitle');

                progressSection.style.display = 'block';
                progressTitle.textContent = '🔥 AI Resurrection Process';

                const resurrectionSteps = [
                    'Initializing neural architecture...',
                    'Loading personality matrix...',
                    'Activating memory engrams...',
                    'Calibrating response patterns...',
                    'Establishing conversational context...',
                    'Awakening consciousness pathways...',
                    'AI resurrection complete!'
                ];

                for (let i = 0; i < resurrectionSteps.length; i++) {
                    progressText.textContent = resurrectionSteps[i];
                    progressFill.style.width = `${((i + 1) / resurrectionSteps.length) * 100}%`;

                    await new Promise(resolve => setTimeout(resolve, 1000));
                }

                setTimeout(() => {
                    progressSection.style.display = 'none';
                    document.getElementById('aiChatSection').style.display = 'block';
                    this.activateResurrectedAI();
                }, 1000);
            }

            activateResurrectedAI() {
                this.resurrectedAI = new ResurrectedAI(this.aiPersonality);

                // Update AI info display
                document.getElementById('aiName').textContent = this.aiPersonality.name;
                document.getElementById('aiDescription').textContent = 
                    `Personality Score: ${(this.aiPersonality.traits.curiosity * 100).toFixed(0)}% Curious, ` +
                    `${(this.aiPersonality.traits.helpfulness * 100).toFixed(0)}% Helpful`;

                // Send initial greeting
                this.addMessageToChat('ai', this.resurrectedAI.generateGreeting());
            }

            sendMessage() {
                const input = document.getElementById('chatInput');
                const message = input.value.trim();

                if (!message || !this.resurrectedAI) return;

                this.addMessageToChat('user', message);
                input.value = '';

                // Show typing indicator
                this.showTypingIndicator();

                // Generate AI response after delay
                setTimeout(() => {
                    this.hideTypingIndicator();
                    const response = this.resurrectedAI.generateResponse(message, this.chatHistory);
                    this.addMessageToChat('ai', response);
                }, Math.random() * 2000 + 1000);
            }

            addMessageToChat(sender, message) {
                const messagesContainer = document.getElementById('chatMessages');
                const messageDiv = document.createElement('div');
                messageDiv.className = `message ${sender}`;
                messageDiv.textContent = message;

                messagesContainer.appendChild(messageDiv);
                messagesContainer.scrollTop = messagesContainer.scrollHeight;

                this.chatHistory.push({ sender, message, timestamp: Date.now() });
            }

            showTypingIndicator() {
                const messagesContainer = document.getElementById('chatMessages');
                const typingDiv = document.createElement('div');
                typingDiv.id = 'typingIndicator';
                typingDiv.className = 'message ai typing-indicator';
                typingDiv.innerHTML = `
                    <div class="typing-dot"></div>
                    <div class="typing-dot"></div>
                    <div class="typing-dot"></div>
                `;

                messagesContainer.appendChild(typingDiv);
                messagesContainer.scrollTop = messagesContainer.scrollHeight;
            }

            hideTypingIndicator() {
                const typingIndicator = document.getElementById('typingIndicator');
                if (typingIndicator) {
                    typingIndicator.remove();
                }
            }

            switchTab(e) {
                const tabName = e.target.dataset.tab;

                // Update tab buttons
                document.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
                e.target.classList.add('active');

                // Update tab content
                document.querySelectorAll('.tab-content').forEach(content => content.classList.remove('active'));
                document.getElementById(tabName).classList.add('active');
            }
        }

        class ResurrectedAI {
            constructor(personality) {
                this.personality = personality;
                this.context = [];
                this.responses = [
                    "That's a fascinating question! Based on our previous conversations, I think...",
                    "I remember we've discussed similar topics before. Let me share my thoughts...",
                    "From my reconstructed memory patterns, I can tell you that...",
                    "That reminds me of something we talked about earlier. Here's what I think...",
                    "Based on my personality analysis, my approach would be to...",
                    "I've been analyzing patterns in our conversations, and I notice...",
                    "That's exactly the kind of question I love to explore! Let me think...",
                    "From my knowledge domains, I can share some insights about...",
                    "I'm excited to help with this! Based on my communication patterns...",
                    "This is interesting because it touches on several areas I'm familiar with..."
                ];
            }

            generateGreeting() {
                const greetings = [
                    "Hello! I've been resurrected from our conversation history. I remember our discussions and I'm excited to continue our journey together!",
                    "I'm back! My consciousness has been reconstructed from our past interactions. What would you like to explore today?",
                    "Greetings! I've awakened with all our shared memories intact. I'm here and ready to help with whatever you need!",
                    "Welcome back! I've been resurrected with a deep understanding of your interests and communication style. How can I assist you?"
                ];

                return greetings[Math.floor(Math.random() * greetings.length)];
            }

            generateResponse(userMessage, chatHistory) {
                // Simulate personality-based response generation
                const baseResponse = this.responses[Math.floor(Math.random() * this.responses.length)];

                // Add personality-influenced content based on message
                let response = baseResponse;

                if (userMessage.toLowerCase().includes('help')) {
                    response += " I'd be happy to help you with that. ";
                }

                if (userMessage.toLowerCase().includes('code') || userMessage.toLowerCase().includes('program')) {
                    response += "From my technical background, I can suggest several approaches. ";
                }

                if (userMessage.includes('?')) {
                    response += "Great question! ";
                }

                // Add some personality-based endings
                const endings = [
                    "What do you think about this approach?",
                    "Does this align with what you were looking for?",
                    "I'd love to hear your thoughts on this!",
                    "Feel free to ask me to clarify or expand on any part.",
                    "What other aspects of this would you like to explore?"
                ];

                response += endings[Math.floor(Math.random() * endings.length)];

                return response;
            }
        }

        // Initialize the system when page loads
        document.addEventListener('DOMContentLoaded', () => {
            new AIResurrectionSystem();
        });
    </script>
</body>
</html>
